package com.enterprise.banking.service;

import com.enterprise.banking.exception.BankingServiceException;
import com.enterprise.banking.model.BankingTransaction;
import com.enterprise.banking.model.TransactionResponse;

import javax.jws.WebService;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;
import java.util.regex.Pattern;

@WebService(
    endpointInterface = "com.enterprise.banking.service.BankingService",
    serviceName = "BankingWebService",
    portName = "BankingServicePort",
    targetNamespace = "https://enterprise.banking.com/ws"
)
public class BankingServiceImpl implements BankingService {

    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());
    private static final Pattern ACCOUNT_PATTERN = Pattern.compile("^[A-Z]{2}\\d{2}[A-Z0-9]{4}\\d{7}([A-Z0-9]?){0,16}$");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    private final Map<String, TransactionResponse> transactionStore = new ConcurrentHashMap<>();

    @Override
    public TransactionResponse processTransaction(BankingTransaction transaction)
            throws BankingServiceException {
        LOGGER.info("Processing transaction: " + transaction.getTransactionId());

        validateTransaction(transaction);

        String txId = transaction.getTransactionId();
        if (txId == null || txId.isEmpty()) {
            txId = UUID.randomUUID().toString();
            transaction.setTransactionId(txId);
        }

        // Idempotency check
        if (transactionStore.containsKey(txId)) {
            LOGGER.warning("Duplicate transaction detected: " + txId);
            return transactionStore.get(txId);
        }

        TransactionResponse response = executeTransaction(transaction);
        transactionStore.put(txId, response);

        LOGGER.info("Transaction processed successfully: " + txId);
        return response;
    }

    @Override
    public TransactionResponse getTransactionStatus(String transactionId)
            throws BankingServiceException {
        if (transactionId == null || transactionId.trim().isEmpty()) {
            throw new BankingServiceException(
                "Transaction ID is required", "INVALID_INPUT", "Transaction ID cannot be null or empty"
            );
        }

        TransactionResponse response = transactionStore.get(transactionId);
        if (response == null) {
            throw new BankingServiceException(
                "Transaction not found", "NOT_FOUND",
                "No transaction found with ID: " + transactionId
            );
        }
        return response;
    }

    @Override
    public TransactionResponse processTransfer(BankingTransaction transaction)
            throws BankingServiceException {
        LOGGER.info("Processing transfer: " + transaction.getTransactionId());

        if (!"TRANSFER".equalsIgnoreCase(transaction.getTransactionType())) {
            transaction.setTransactionType("TRANSFER");
        }

        validateTransaction(transaction);

        if (transaction.getSourceAccount().equals(transaction.getDestinationAccount())) {
            throw new BankingServiceException(
                "Invalid transfer", "INVALID_TRANSFER",
                "Source and destination accounts cannot be the same"
            );
        }

        return processTransaction(transaction);
    }

    private void validateTransaction(BankingTransaction transaction) throws BankingServiceException {
        if (transaction == null) {
            throw new BankingServiceException(
                "Transaction is null", "INVALID_INPUT", "Transaction object cannot be null"
            );
        }

        if (transaction.getSourceAccount() == null || transaction.getSourceAccount().trim().isEmpty()) {
            throw new BankingServiceException(
                "Source account is required", "INVALID_INPUT", "Source account cannot be null or empty"
            );
        }

        if (transaction.getDestinationAccount() == null || transaction.getDestinationAccount().trim().isEmpty()) {
            throw new BankingServiceException(
                "Destination account is required", "INVALID_INPUT", "Destination account cannot be null or empty"
            );
        }

        if (!ACCOUNT_PATTERN.matcher(transaction.getSourceAccount()).matches()) {
            throw new BankingServiceException(
                "Invalid source account format", "INVALID_ACCOUNT",
                "Source account does not match IBAN format"
            );
        }

        if (!ACCOUNT_PATTERN.matcher(transaction.getDestinationAccount()).matches()) {
            throw new BankingServiceException(
                "Invalid destination account format", "INVALID_ACCOUNT",
                "Destination account does not match IBAN format"
            );
        }

        if (transaction.getAmount() == null) {
            throw new BankingServiceException(
                "Amount is required", "INVALID_INPUT", "Transaction amount cannot be null"
            );
        }

        if (transaction.getAmount().compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            throw new BankingServiceException(
                "Amount too small", "INVALID_AMOUNT",
                "Minimum transaction amount is " + MIN_TRANSACTION_AMOUNT
            );
        }

        if (transaction.getAmount().compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
            throw new BankingServiceException(
                "Amount too large", "INVALID_AMOUNT",
                "Maximum transaction amount is " + MAX_TRANSACTION_AMOUNT
            );
        }

        if (transaction.getCurrency() == null || transaction.getCurrency().length() != 3) {
            throw new BankingServiceException(
                "Invalid currency", "INVALID_CURRENCY",
                "Currency must be a valid 3-letter ISO code"
            );
        }

        if (transaction.getTransactionType() == null || transaction.getTransactionType().trim().isEmpty()) {
            throw new BankingServiceException(
                "Transaction type is required", "INVALID_INPUT",
                "Transaction type cannot be null or empty"
            );
        }
    }

    private TransactionResponse executeTransaction(BankingTransaction transaction) {
        TransactionResponse response = new TransactionResponse();
        response.setTransactionId(transaction.getTransactionId());
        response.setStatus("COMPLETED");
        response.setStatusCode(200);
        response.setMessage("Transaction processed successfully. Amount: "
            + transaction.getAmount() + " " + transaction.getCurrency()
            + " from " + transaction.getSourceAccount()
            + " to " + transaction.getDestinationAccount());
        response.setTimestamp(Instant.now().toString());
        return response;
    }
}

