package com.enterprise.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

import javax.xml.namespace.QName;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathExpression;
import javax.xml.xpath.XPathFactory;
import javax.xml.xpath.XPathExpressionException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Iterator;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.logging.Logger;

import javax.xml.namespace.NamespaceContext;

public class SignatureWrappingPreventionInterceptor extends AbstractSoapInterceptor {

    private static final Logger LOGGER = Logger.getLogger(
        SignatureWrappingPreventionInterceptor.class.getName());

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String DS_NS = "http://www.w3.org/2000/09/xmldsig#";
    private static final String SOAP_ENV_NS = "http://schemas.xmlsoap.org/soap/envelope/";
    private static final String SOAP12_ENV_NS = "http://www.w3.org/2003/05/soap-envelope";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    // Expected structure: maps wsu:Id values to their expected parent element local names
    private final Map<String, String> expectedElementPositions;
    private final int maxAllowedElements;

    public SignatureWrappingPreventionInterceptor() {
        super(Phase.PRE_PROTOCOL);
        this.expectedElementPositions = new HashMap<>();
        this.maxAllowedElements = 50;
    }

    public SignatureWrappingPreventionInterceptor(Map<String, String> expectedPositions) {
        super(Phase.PRE_PROTOCOL);
        this.expectedElementPositions = expectedPositions != null ? expectedPositions : new HashMap<>();
        this.maxAllowedElements = 50;
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            Document doc = message.getContent(org.w3c.dom.Document.class);
            if (doc == null) {
                // Try to get from SOAPMessage
                javax.xml.soap.SOAPMessage soapMsg = message.getContent(javax.xml.soap.SOAPMessage.class);
                if (soapMsg != null) {
                    doc = soapMsg.getSOAPPart();
                }
            }

            if (doc == null) {
                LOGGER.warning("No document found in message - skipping wrapping check");
                return;
            }

            validateDocumentStructure(doc);
            validateNoWrappingAttack(doc);
            validateSignatureReferences(doc);
            validateUniqueIds(doc);
            validateElementCount(doc);
            validateNoExtraSecurityHeaders(doc);

            LOGGER.info("SOAP message passed all signature wrapping prevention checks");

        } catch (SecurityException e) {
            LOGGER.severe("Signature wrapping attack detected: " + e.getMessage());
            throw new Fault(new SecurityException("Message rejected: " + e.getMessage()));
        } catch (Exception e) {
            LOGGER.severe("Error during signature wrapping validation: " + e.getMessage());
            throw new Fault(new SecurityException("Message validation failed"));
        }
    }

    /**
     * Validates the overall SOAP document structure to ensure it conforms
     * to expected schema: Envelope -> Header + Body, no extra top-level elements.
     */
    private void validateDocumentStructure(Document doc) {
        Element root = doc.getDocumentElement();
        if (root == null) {
            throw new SecurityException("Empty SOAP document");
        }

        String rootNs = root.getNamespaceURI();
        String rootLocal = root.getLocalName();

        if (!"Envelope".equals(rootLocal) ||
            (!SOAP_ENV_NS.equals(rootNs) && !SOAP12_ENV_NS.equals(rootNs))) {
            throw new SecurityException("Invalid SOAP envelope structure");
        }

        // Verify Envelope has at most one Header and exactly one Body
        int headerCount = 0;
        int bodyCount = 0;
        int unexpectedChildren = 0;

        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }
            Element childElem = (Element) child;
            String childNs = childElem.getNamespaceURI();
            String childLocal = childElem.getLocalName();

            if (!rootNs.equals(childNs)) {
                unexpectedChildren++;
                continue;
            }

            if ("Header".equals(childLocal)) {
                headerCount++;
            } else if ("Body".equals(childLocal)) {
                bodyCount++;
            } else {
                unexpectedChildren++;
            }
        }

        if (headerCount > 1) {
            throw new SecurityException("Multiple SOAP Header elements detected - possible wrapping attack");
        }
        if (bodyCount != 1) {
            throw new SecurityException("Expected exactly one SOAP Body element, found: " + bodyCount);
        }
        if (unexpectedChildren > 0) {
            throw new SecurityException("Unexpected elements found as children of SOAP Envelope");
        }
    }

    /**
     * Core wrapping attack prevention: ensures that each signed element (referenced by wsu:Id)
     * appears exactly once in the document and is in its expected position within the SOAP structure.
     */
    private void validateNoWrappingAttack(Document doc) {
        // Collect all elements with wsu:Id attributes
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");
        Map<String, List<Element>> idToElements = new HashMap<>();

        for (int i = 0; i < allElements.getLength(); i++) {
            Element elem = (Element) allElements.item(i);

            // Check wsu:Id
            String wsuId = elem.getAttributeNS(WSU_NS, "Id");
            if (wsuId != null && !wsuId.isEmpty()) {
                idToElements.computeIfAbsent(wsuId, k -> new ArrayList<>()).add(elem);
            }

            // Also check xml:id and plain Id attribute
            String xmlId = elem.getAttribute("Id");
            if (xmlId != null && !xmlId.isEmpty()) {
                idToElements.computeIfAbsent(xmlId, k -> new ArrayList<>()).add(elem);
            }
        }

        // Verify each ID appears exactly once
        for (Map.Entry<String, List<Element>> entry : idToElements.entrySet()) {
            if (entry.getValue().size() > 1) {
                throw new SecurityException(
                    "Duplicate wsu:Id detected: '" + entry.getKey()
                    + "' appears " + entry.getValue().size()
                    + " times - possible signature wrapping attack"
                );
            }
        }

        // Verify signed elements are in expected positions
        for (Map.Entry<String, List<Element>> entry : idToElements.entrySet()) {
            String id = entry.getKey();
            Element elem = entry.getValue().get(0);

            validateElementPosition(elem, id, doc);
        }
    }

    /**
     * Validates that an element with a given wsu:Id is in its expected position
     * within the SOAP message structure.
     */
    private void validateElementPosition(Element elem, String id, Document doc) {
        String localName = elem.getLocalName();
        String namespaceURI = elem.getNamespaceURI();

        // Body element must be direct child of Envelope
        if ("Body".equals(localName) &&
            (SOAP_ENV_NS.equals(namespaceURI) || SOAP12_ENV_NS.equals(namespaceURI))) {
            Node parent = elem.getParentNode();
            if (parent == null || !"Envelope".equals(parent.getLocalName())) {
                throw new SecurityException(
                    "SOAP Body with Id '" + id + "' is not a direct child of Envelope"
                );
            }
            return;
        }

        // Timestamp must be inside Security header
        if ("Timestamp".equals(localName) && WSU_NS.equals(namespaceURI)) {
            if (!isInsideSecurityHeader(elem)) {
                throw new SecurityException(
                    "Timestamp with Id '" + id + "' is not inside WS-Security header"
                );
            }
            return;
        }

        // BinarySecurityToken must be inside Security header
        if ("BinarySecurityToken".equals(localName) && WSSE_NS.equals(namespaceURI)) {
            if (!isInsideSecurityHeader(elem)) {
                throw new SecurityException(
                    "BinarySecurityToken with Id '" + id + "' is not inside WS-Security header"
                );
            }
            return;
        }

        // UsernameToken must be inside Security header
        if ("UsernameToken".equals(localName) && WSSE_NS.equals(namespaceURI)) {
            if (!isInsideSecurityHeader(elem)) {
                throw new SecurityException(
                    "UsernameToken with Id '" + id + "' is not inside WS-Security header"
                );
            }
            return;
        }

        // Check custom expected positions
        if (expectedElementPositions.containsKey(id)) {
            String expectedParent = expectedElementPositions.get(id);
            Node parent = elem.getParentNode();
            if (parent == null || !expectedParent.equals(parent.getLocalName())) {
                throw new SecurityException(
                    "Element with Id '" + id + "' expected parent '" + expectedParent
                    + "' but found '" + (parent != null ? parent.getLocalName() : "null") + "'"
                );
            }
        }

        // General check: signed elements should be inside Header or Body, not floating
        if (!isInsideSoapHeaderOrBody(elem)) {
            throw new SecurityException(
                "Element with Id '" + id + "' ('" + localName
                + "') is not inside SOAP Header or Body - possible wrapping attack"
            );
        }
    }

    /**
     * Checks if an element is a descendant of a wsse:Security header.
     */
    private boolean isInsideSecurityHeader(Element elem) {
        Node current = elem.getParentNode();
        while (current != null && current.getNodeType() == Node.ELEMENT_NODE) {
            if ("Security".equals(current.getLocalName()) && WSSE_NS.equals(current.getNamespaceURI())) {
                // Also verify Security is inside Header
                Node secParent = current.getParentNode();
                if (secParent != null && "Header".equals(secParent.getLocalName())) {
                    String secParentNs = secParent.getNamespaceURI();
                    return SOAP_ENV_NS.equals(secParentNs) || SOAP12_ENV_NS.equals(secParentNs);
                }
                return false;
            }
            current = current.getParentNode();
        }
        return false;
    }

    /**
     * Checks if an element is a descendant of SOAP Header or Body.
     */
    private boolean isInsideSoapHeaderOrBody(Element elem) {
        Node current = elem.getParentNode();
        while (current != null && current.getNodeType() == Node.ELEMENT_NODE) {
            String localName = current.getLocalName();
            String ns = current.getNamespaceURI();
            if (("Header".equals(localName) || "Body".equals(localName)) &&
                (SOAP_ENV_NS.equals(ns) || SOAP12_ENV_NS.equals(ns))) {
                return true;
            }
            current = current.getParentNode();
        }
        return false;
    }

    /**
     * Validates that all ds:Reference URI values in signatures point to elements
     * that actually exist and are properly positioned.
     */
    private void validateSignatureReferences(Document doc) {
        NodeList references = doc.getElementsByTagNameNS(DS_NS, "Reference");

        for (int i = 0; i < references.getLength(); i++) {
            Element ref = (Element) references.item(i);
            String uri = ref.getAttribute("URI");

            if (uri == null || uri.isEmpty()) {
                continue;
            }

            // URI should start with # for local references
            if (!uri.startsWith("#")) {
                throw new SecurityException(
                    "External signature reference detected: '" + uri
                    + "' - only local references are allowed"
                );
            }

            String refId = uri.substring(1);

            // Find the referenced element
            Element referencedElement = findElementById(doc, refId);
            if (referencedElement == null) {
                throw new SecurityException(
                    "Signature reference '" + uri + "' points to non-existent element"
                );
            }

            // Verify the Signature element itself is inside the Security header
            Element signatureElem = findAncestorSignature(ref);
            if (signatureElem != null && !isInsideSecurityHeader(signatureElem)) {
                throw new SecurityException(
                    "Signature element is not inside WS-Security header"
                );
            }

            // Verify the referenced element is reachable from the document root
            // through the expected SOAP structure
            if (!isReachableFromDocumentRoot(referencedElement, doc)) {
                throw new SecurityException(
                    "Referenced element '" + refId + "' is not properly connected to document root"
                );
            }
        }
    }

    /**
     * Finds an element by its wsu:Id or Id attribute.
     */
    private Element findElementById(Document doc, String id) {
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");
        Element found = null;
        int count = 0;

        for (int i = 0; i < allElements.getLength(); i++) {
            Element elem = (Element) allElements.item(i);
            String wsuId = elem.getAttributeNS(WSU_NS, "Id");
            String plainId = elem.getAttribute("Id");

            if (id.equals(wsuId) || id.equals(plainId)) {
                found = elem;
                count++;
            }
        }

        if (count > 1) {
            throw new SecurityException(
                "Multiple elements found with Id '" + id + "' - possible wrapping attack"
            );
        }

        return found;
    }

    /**
     * Finds the ancestor ds:Signature element of a given node.
     */
    private Element findAncestorSignature(Node node) {
        Node current = node.getParentNode();
        while (current != null && current.getNodeType() == Node.ELEMENT_NODE) {
            if ("Signature".equals(current.getLocalName()) && DS_NS.equals(current.getNamespaceURI())) {
                return (Element) current;
            }
            current = current.getParentNode();
        }
        return null;
    }

    /**
     * Verifies that an element is reachable from the document root through
     * the proper DOM tree (not a detached or injected subtree).
     */
    private boolean isReachableFromDocumentRoot(Element elem, Document doc) {
        Node current = elem;
        while (current != null) {
            if (current == doc.getDocumentElement()) {
                return true;
            }
            current = current.getParentNode();
        }
        return false;
    }

    /**
     * Ensures all wsu:Id values in the document are unique.
     */
    private void validateUniqueIds(Document doc) {
        Set<String> seenIds = new HashSet<>();
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");

        for (int i = 0; i < allElements.getLength(); i++) {
            Element elem = (Element) allElements.item(i);

            String wsuId = elem.getAttributeNS(WSU_NS, "Id");
            if (wsuId != null && !wsuId.isEmpty()) {
                if (!seenIds.add(wsuId)) {
                    throw new SecurityException(
                        "Duplicate wsu:Id value: '" + wsuId + "' - possible wrapping attack"
                    );
                }
            }

            String plainId = elem.getAttribute("Id");
            if (plainId != null && !plainId.isEmpty() &&
                !plainId.equals(wsuId)) {
                if (!seenIds.add(plainId)) {
                    throw new SecurityException(
                        "Duplicate Id value: '" + plainId + "' - possible wrapping attack"
                    );
                }
            }
        }
    }

    /**
     * Prevents DoS by limiting the total number of elements in the document.
     */
    private void validateElementCount(Document doc) {
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");
        if (allElements.getLength() > maxAllowedElements) {
            throw new SecurityException(
                "Document contains too many elements (" + allElements.getLength()
                + ") - possible attack"
            );
        }
    }

    /**
     * Ensures there is at most one wsse:Security header per SOAP actor/role.
     */
    private void validateNoExtraSecurityHeaders(Document doc) {
        NodeList securityHeaders = doc.getElementsByTagNameNS(WSSE_NS, "Security");
        if (securityHeaders.getLength() > 1) {
            // Check if they target different actors/roles
            Set<String> actors = new HashSet<>();
            for (int i = 0; i < securityHeaders.getLength(); i++) {
                Element secHeader = (Element) securityHeaders.item(i);
                String actor = secHeader.getAttributeNS(SOAP_ENV_NS, "actor");
                if (actor == null || actor.isEmpty()) {
                    actor = secHeader.getAttributeNS(SOAP12_ENV_NS, "role");
                }
                if (actor == null || actor.isEmpty()) {
                    actor = "__default__";
                }
                if (!actors.add(actor)) {
                    throw new SecurityException(
                        "Multiple Security headers found for the same actor/role - possible wrapping attack"
                    );
                }
            }
        }
    }
}

// ==================== SOAPMessageValidator.java ====================
package com.enterprise.banking.security;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import java.io.ByteArrayInputStream;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;
import java.util.logging.Logger;

public class SOAPMessageValidator {

    private static final Logger LOGGER = Logger.getLogger(SOAPMessageValidator.class.getName());
    private static final String DS_NS = "http://www.w3.org/2000/09/xmldsig#";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    /**
     * Parses a SOAP message from bytes using secure parser settings.
     */
    public Document parseSOAPMessage(byte[] soapMessageBytes) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);

        // Prevent XXE attacks
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        dbf.setXIncludeAware(false);
        dbf.setExpandEntityReferences(false);

        DocumentBuilder db = dbf.newDocumentBuilder();
        return db.parse(new ByteArrayInputStream(soapMessageBytes));
    }

    /**
     * Extracts signed element references from the SOAP message.
     */
    public List<SignedElementInfo> extractSignedElements(Document doc) throws Exception {
        List<SignedElementInfo> signedElements = new ArrayList<>();

        NodeList signatureNodes = doc.getElementsByTagNameNS(DS_NS, "Signature");

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElem = (Element) signatureNodes.item(i);

            NodeList referenceNodes = signatureElem.getElementsByTagNameNS(DS_NS, "Reference");

            for (int j = 0; j < referenceNodes.getLength(); j++) {
                Element refElem = (Element) referenceNodes.item(j);
                String uri = refElem.getAttribute("URI");

                if (uri != null && uri.startsWith("#")) {
                    String refId = uri.substring(1);
                    Element referencedElement = findElementByWsuId(doc, refId);

                    if (referencedElement != null) {
                        SignedElementInfo info = new SignedElementInfo();
                        info.setReferenceUri(uri);
                        info.setElementId(refId);
                        info.setElementLocalName(referencedElement.getLocalName());
                        info.setElementNamespace(referencedElement.getNamespaceURI());
                        info.setElement(referencedElement);

                        // Extract digest method and value
                        NodeList digestMethods = refElem.getElementsByTagNameNS(DS_NS, "DigestMethod");
                        if (digestMethods.getLength() > 0) {
                            info.setDigestAlgorithm(
                                ((Element) digestMethods.item(0)).getAttribute("Algorithm")
                            );
                        }

                        NodeList digestValues = refElem.getElementsByTagNameNS(DS_NS, "DigestValue");
                        if (digestValues.getLength() > 0) {
                            info.setDigestValue(digestValues.item(0).getTextContent());
                        }

                        signedElements.add(info);
                    }
                }
            }
        }

        return signedElements;
    }

    /**
     * Verifies XML digital signatures in the document using the Java XML Digital Signature API.
     */
    public boolean verifySignatures(Document doc, PublicKey publicKey) throws Exception {
        NodeList signatureNodes = doc.getElementsByTagNameNS(DS_NS, "Signature");

        if (signatureNodes.getLength() == 0) {
            LOGGER.warning("No signatures found in document");
            return false;
        }

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElem = (Element) signatureNodes.item(i);

            DOMValidateContext valContext = new DOMValidateContext(publicKey, signatureElem);

            // Register ID attributes for wsu:Id resolution
            registerWsuIds(doc, valContext);

            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = factory.unmarshalXMLSignature(valContext);

            boolean coreValid = signature.validate(valContext);

            if (!coreValid) {
                LOGGER.severe("Signature validation failed for signature #" + i);

                // Check signature value validity
                boolean signatureValueValid = signature.getSignatureValue().validate(valContext);
                LOGGER.info("Signature value validity: " + signatureValueValid);

                // Check each reference
                @SuppressWarnings("unchecked")
                List<Reference> refs = signature.getSignedInfo().getReferences();
                for (Reference ref : refs) {
                    boolean refValid = ref.validate(valContext);
                    LOGGER.info("Reference '" + ref.getURI() + "' validity: " + refValid);
                }

                return false;
            }

            LOGGER.info("Signature #" + i + " validated successfully");
        }

        return true;
    }

    /**
     * Verifies signatures using certificates embedded in the KeyInfo.
     */
    public boolean verifySignaturesWithEmbeddedCerts(Document doc) throws Exception {
        NodeList signatureNodes = doc.getElementsByTagNameNS(DS_NS, "Signature");

        if (signatureNodes.getLength() == 0) {
            return false;
        }

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElem = (Element) signatureNodes.item(i);

            DOMValidateContext valContext = new DOMValidateContext(
                new KeyValueKeySelector(), signatureElem
            );

            registerWsuIds(doc, valContext);

            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = factory.unmarshalXMLSignature(valContext);

            if (!signature.validate(valContext)) {
                LOGGER.severe("Signature validation failed for signature #" + i);
                return false;
            }
        }

        return true;
    }

    /**
     * Registers all wsu:Id attributes with the validation context so that
     * URI references (#id) can be resolved properly.
     */
    private void registerWsuIds(Document doc, DOMValidateContext valContext) {
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element elem = (Element) allElements.item(i);
            String wsuId = elem.getAttributeNS(WSU_NS, "Id");
            if (wsuId != null && !wsuId.isEmpty()) {
                valContext.setIdAttributeNS(elem, WSU_NS, "Id");
            }
            // Also handle plain Id attributes
            if (elem.hasAttribute("Id")) {
                elem.setIdAttribute("Id", true);
            }
        }
    }

    private Element findElementByWsuId(Document doc, String id) {
        NodeList allElements = doc.getElementsByTagNameNS("*", "*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element elem = (Element) allElements.item(i);
            String wsuId = elem.getAttributeNS(WSU_NS, "Id");
            if (id.equals(wsuId)) {
                return elem;
            }
            String plainId = elem.getAttribute("Id");
            if (id.equals(plainId)) {
                return elem;
            }
        }
        return null;
    }

    /**
     * KeySelector that extracts the public key from X509Data in KeyInfo.
     */
    private static class KeyValueKeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                        AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {

            if (keyInfo == null) {
                throw new KeySelectorException("No KeyInfo found in signature");
            }

            @SuppressWarnings("unchecked")
            List<Object> keyInfoContent = (List<Object>) keyInfo.getContent();
            for (Object content : keyInfoContent) {
                if (content instanceof X509Data) {
                    X509Data x509Data = (X509Data) content;
                    @SuppressWarnings("unchecked")
                    List<Object> x509Content = (List<Object>) x509Data.getContent();
                    for (Object x509Obj : x509Content) {
                        if (x509Obj instanceof X509Certificate) {
                            final PublicKey pk = ((X509Certificate) x509Obj).getPublicKey();
                            return () -> pk;
                        }
                    }
                }
            }

            throw new KeySelectorException("No suitable key found in KeyInfo");
        }
    }

    /**
     * Data class holding information about a signed element.
     */
    public static class SignedElementInfo {
        private String referenceUri;
        private String elementId;
        private String elementLocalName;
        private String elementNamespace;
        private String digestAlgorithm;
        private String digestValue;
        private Element element;

        public String getReferenceUri() { return referenceUri; }
        public void setReferenceUri(String referenceUri) { this.referenceUri = referenceUri; }
        public String getElementId() { return elementId; }
        public void setElementId(String elementId) { this.elementId = elementId; }
        public String getElementLocalName() { return elementLocalName; }
        public void setElementLocalName(String elementLocalName) { this.elementLocalName = elementLocalName; }
        public String getElementNamespace() { return elementNamespace; }
        public void setElementNamespace(String elementNamespace) { this.elementNamespace = elementNamespace; }
        public String getDigestAlgorithm() { return digestAlgorithm; }
        public void setDigestAlgorithm(String digestAlgorithm) { this.digestAlgorithm = digestAlgorithm; }
        public String getDigestValue() { return digestValue; }
        public void setDigestValue(String digestValue) { this.digestValue = digestValue; }
        public Element getElement() { return element; }
        public void setElement(Element element) { this.element = element; }

        @Override
        public String toString() {
            return "SignedElementInfo{" +
                "referenceUri='" + referenceUri + '\'' +
                ", elementId='" + elementId + '\'' +
                ", elementLocalName='" + elementLocalName + '\'' +
                ", elementNamespace='" + elementNamespace + '\'' +
                ", digestAlgorithm='" + digestAlgorithm + '\'' +
                '}';
        }
    }
}

// ==================== WSSPasswordCallback.java ====================
package com.enterprise.banking.security;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.logging.Logger;

import org.apache.wss4j.common.ext.WSPasswordCallback;

public class WSSPasswordCallback implements CallbackHandler {

    private static final Logger LOGGER = Logger.getLogger(WSSPasswordCallback.class.getName());

    // In production, these would come from a secure vault/HSM
    private static final String KEYSTORE_PASSWORD = "changeit";
    private static final String KEY_PASSWORD = "changeit";

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String identifier = pc.getIdentifier();

                LOGGER.info("Password callback for identifier: " + identifier);

                switch (pc.getUsage()) {
                    case WSPasswordCallback.DECRYPT:
                    case WSPasswordCallback.SIGNATURE:
                        pc.setPassword(KEY_PASSWORD);
                        break;
                    case WSPasswordCallback.USERNAME_TOKEN:
                        // Validate username token - in production, check against user store
                        if ("bankingServiceUser".equals(identifier)) {
                            pc.setPassword("securePassword123");
                        }
                        break;
                    default:
                        pc.setPassword(KEYSTORE_PASSWORD);
                        break;
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unrecognized callback type");
            }
        }
    }
}

// ==================== SecurityConfigurationManager.java ====================
package com.enterprise.banking.security;

import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;
import org.apache.wss4j.dom.WSConstants;

import java.util.HashMap;
import java.util.Map;

public class SecurityConfigurationManager {

    private static final String KEYSTORE_FILE = "banking-keystore.jks";
    private static final String TRUSTSTORE_FILE = "banking-truststore.jks";
    private static final String KEYSTORE_TYPE = "JKS";
    private static final String CRYPTO_PROVIDER = "org.apache.wss4j.common.crypto.Merlin";

    /**
     * Creates the inbound WSS4J interceptor for verifying incoming signed messages.
     */
    public WSS4JInInterceptor createInboundSecurityInterceptor() {
        Map<String, Object> inProps = new HashMap<>();

        // Actions: Timestamp verification + Signature verification + Encryption
        inProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT
        );

        // Signature verification properties
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");

        // Decryption properties
        inProps.put(WSHandlerConstants.DEC_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
            WSSPasswordCallback.class.getName());

        // Enforce BSP compliance
        inProps.put(WSHandlerConstants.IS_BSP_COMPLIANT, "true");

        // Require signed Body and Timestamp
        inProps.put(WSHandlerConstants.SIG_ALGO, WSConstants.RSA_SHA256);
        inProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, WSConstants.SHA256);

        // Timestamp validation - 5 minute tolerance
        inProps.put(WSHandlerConstants.TTL_TIMESTAMP, "300");
        inProps.put(WSHandlerConstants.TIMESTAMP_STRICT, "true");

        // Require timestamp to be signed
        inProps.put(WSHandlerConstants.REQUIRE_SIGNED_ENCRYPTED_DATA_ELEMENTS, "true");

        return new WSS4JInInterceptor(inProps);
    }

    /**
     * Creates the outbound WSS4J interceptor for signing outgoing messages.
     */
    public WSS4JOutInterceptor createOutboundSecurityInterceptor() {
        Map<String, Object> outProps = new HashMap<>();

        // Actions: Add Timestamp + Sign + Encrypt
        outProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT
        );

        // Signing properties
        outProps.put(WSHandlerConstants.USER, "bankingServiceKey");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        outProps.put(WSHandlerConstants.SIG_ALGO, WSConstants.RSA_SHA256);
        outProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, WSConstants.SHA256);

        // Sign Body and Timestamp
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
            "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
            "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp"
        );

        // Encryption properties
        outProps.put(WSHandlerConstants.ENC_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.ENCRYPTION_USER, "useReqSigCert");
        outProps.put(WSHandlerConstants.ENC_KEY_TRANSPORT, WSConstants.KEYTRANSPORT_RSAOAEP);
        outProps.put(WSHandlerConstants.ENC_SYM_ALGO, WSConstants.AES_256);

        outProps.put(WSHandlerConstants.ENCRYPTION_PARTS,
            "{Content}{http://schemas.xmlsoap.org/soap/envelope/}Body"
        );

        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
            WSSPasswordCallback.class.getName());

        return new WSS4JOutInterceptor(outProps);
    }

    /**
     * Creates crypto properties for the keystore configuration.
     * In production, this would be loaded from a properties file.
     */
    public Map<String, String> createCryptoProperties() {
        Map<String, String> props = new HashMap<>();
        props.put("org.apache.wss4j.crypto.provider", CRYPTO_PROVIDER);
        props.put("org.apache.wss4j.crypto.merlin.keystore.type", KEYSTORE_TYPE);
        props.put("org.apache.wss4j.crypto.merlin.keystore.file", KEYSTORE_FILE);
        props.put("org.apache.wss4j.crypto.merlin.keystore.password", "changeit");
        props.put("org.apache.wss4j.crypto.merlin.keystore.alias", "bankingServiceKey");
        props.put("org.apache.wss4j.crypto.merlin.truststore.type", KEYSTORE_TYPE);
        props.put("org.apache.wss4j.crypto.merlin.truststore.file", TRUSTSTORE_FILE);
        props.put("org.apache.wss4j.crypto.merlin.truststore.password", "changeit");
        return props;
    }
}

// ==================== TransactionRequestProcessor.java ====================
package com.enterprise.banking.processing;

import com.enterprise.banking.model.BankingTransaction;
import com.enterprise.banking.model.TransactionResponse;
import com.enterprise.banking.security.SOAPMessageValidator;
import com.enterprise.banking.security.SOAPMessageValidator.SignedElementInfo;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.bind.JAXBContext;
import javax.xml.bind.Unmarshaller;
import java.math.BigDecimal;
import java.security.PublicKey;
import java.time.Instant;
import java.util.List;
import java.util.UUID;
import java.util.logging.Logger;

public class TransactionRequestProcessor {

    private static final Logger LOGGER = Logger.getLogger(TransactionRequestProcessor.class.getName());
    private static final String BANKING_NS = "https://enterprise.banking.com/ws";

    private final SOAPMessageValidator validator;

    public TransactionRequestProcessor() {
        this.validator = new SOAPMessageValidator();
    }

    /**
     * Processes a raw SOAP message: parses, validates signatures, extracts transaction,
     * and returns a response.
     */
    public TransactionResponse processRawSOAPMessage(byte[] soapMessage, PublicKey signerPublicKey)
            throws Exception {

        // Step 1: Parse the SOAP message securely
        Document doc = validator.parseSOAPMessage(soapMessage);
        LOGGER.info("SOAP message parsed successfully");

        // Step 2: Extract and log signed elements
        List<SignedElementInfo> signedElements = validator.extractSignedElements(doc);
        LOGGER.info("Found " + signedElements.size() + " signed elements");

        for (SignedElementInfo info : signedElements) {
            LOGGER.info("Signed element: " + info);
        }

        // Step 3: Verify that required elements are signed
        validateRequiredSignedElements(signedElements);

        // Step 4: Verify XML signatures
        boolean signaturesValid;
        if (signerPublicKey != null) {
            signaturesValid = validator.verifySignatures(doc, signerPublicKey);
        } else {
            signaturesValid = validator.verifySignaturesWithEmbeddedCerts(doc);
        }

        if (!signaturesValid) {
            throw new SecurityException("XML signature verification failed");
        }
        LOGGER.info("All signatures verified successfully");

        // Step 5: Extract the transaction from the SOAP Body
        BankingTransaction transaction = extractTransaction(doc);
        LOGGER.info("Transaction extracted: " + transaction.getTransactionId());

        // Step 6: Process the transaction
        return executeTransaction(transaction);
    }

    /**
     * Validates that the SOAP Body and Timestamp are among the signed elements.
     */
    private void validateRequiredSignedElements(List<SignedElementInfo> signedElements) {
        boolean bodyIsSigned = false;
        boolean timestampIsSigned = false;

        for (SignedElementInfo info : signedElements) {
            if ("Body".equals(info.getElementLocalName())) {
                bodyIsSigned = true;
            }
            if ("Timestamp".equals(info.getElementLocalName())) {
                timestampIsSigned = true;
            }
        }

        if (!bodyIsSigned) {
            throw new SecurityException("SOAP Body is not signed - message rejected");
        }
        if (!timestampIsSigned) {
            throw new SecurityException("Timestamp is not signed - message rejected");
        }

        LOGGER.info("Required elements (Body, Timestamp) are properly signed");
    }

    /**
     * Extracts a BankingTransaction from the SOAP Body.
     */
    private BankingTransaction extractTransaction(Document doc) throws Exception {
        // Find the SOAP Body
        NodeList bodyList = doc.getElementsByTagNameNS(
            "http://schemas.xmlsoap.org/soap/envelope/", "Body");
        if (bodyList.getLength() == 0) {
            bodyList = doc.getElementsByTagNameNS(
                "http://www.w3.org/2003/05/soap-envelope", "Body");
        }

        if (bodyList.getLength() == 0) {
            throw new IllegalStateException("No SOAP Body found");
        }

        Element body = (Element) bodyList.item(0);

        // Find the transaction element within the body
        NodeList transactionElements = body.getElementsByTagNameNS(BANKING_NS, "BankingTransaction");
        if (transactionElements.getLength() == 0) {
            // Try without namespace
            transactionElements = body.getElementsByTagName("BankingTransaction");
        }

        if (transactionElements.getLength() == 0) {
            // Try to find it inside a wrapper element (e.g., processTransaction)
            NodeList wrapperElements = body.getElementsByTagNameNS(BANKING_NS, "processTransaction");
            if (wrapperElements.getLength() > 0) {
                Element wrapper = (Element) wrapperElements.item(0);
                transactionElements = wrapper.getElementsByTagNameNS(BANKING_NS, "transaction");
                if (transactionElements.getLength() == 0) {
                    transactionElements = wrapper.getElementsByTagName("transaction");
                }
            }
        }

        if (transactionElements.getLength() > 0) {
            Element txElement = (Element) transactionElements.item(0);
            return unmarshalTransaction(txElement);
        }

        throw new IllegalStateException("No BankingTransaction element found in SOAP Body");
    }

    /**
     * Unmarshals a BankingTransaction from an XML element.
     */
    private BankingTransaction unmarshalTransaction(Element element) throws Exception {
        try {
            JAXBContext context = JAXBContext.newInstance(BankingTransaction.class);
            Unmarshaller unmarshaller = context.createUnmarshaller();
            return (BankingTransaction) unmarshaller.unmarshal(element);
        } catch (Exception e) {
            // Fallback: manual extraction
            LOGGER.warning("JAXB unmarshalling failed, falling back to manual extraction: " + e.getMessage());
            return manualExtractTransaction(element);
        }
    }

    /**
     * Manually extracts transaction fields from XML element as a fallback.
     */
    private BankingTransaction manualExtractTransaction(Element element) {
        BankingTransaction tx = new BankingTransaction();
        tx.setTransactionId(getElementText(element, "transactionId"));
        tx.setSourceAccount(getElementText(element, "sourceAccount"));
        tx.setDestinationAccount(getElementText(element, "destinationAccount"));

        String amountStr = getElementText(element, "amount");
        if (amountStr != null && !amountStr.isEmpty()) {
            tx.setAmount(new BigDecimal(amountStr));
        }

        tx.setCurrency(getElementText(element, "currency"));
        tx.setTransactionType(getElementText(element, "transactionType"));
        tx.setDescription(getElementText(element, "description"));

        return tx;
    }

    private String getElementText(Element parent, String childName) {
        NodeList children = parent.getElementsByTagName(childName);
        if (children.getLength() == 0) {
            children = parent.getElementsByTagNameNS(BANKING_NS, childName);
        }
        if (children.getLength() > 0) {
            return children.item(0).getTextContent();
        }
        return null;
    }

    private TransactionResponse executeTransaction(BankingTransaction transaction) {
        TransactionResponse response = new TransactionResponse();
        response.setTransactionId(
            transaction.getTransactionId() != null ?
                transaction.getTransactionId() : UUID.randomUUID().toString()
        );
        response.setStatus("COMPLETED");
        response.setStatusCode(200);
        response.setMessage("Transaction processed successfully");
        response.setTimestamp(Instant.now().toString());
        return response;
    }
}

